def validate(args, output):
    num_arrows, alice = args[0], args[1]
    if not isinstance(output, list) or len(output) != 12:
        return False
    for x in output:
        if not isinstance(x, int) or isinstance(x, bool) or x < 0:
            return False
    if sum(output) != num_arrows:
        return False
    score = sum(k for k in range(12) if output[k] > alice[k])
    best = -1
    for mask in range(1 << 12):
        cost = sum(alice[k] + 1 for k in range(12) if (mask >> k) & 1)
        if cost <= num_arrows:
            s = sum(k for k in range(12) if (mask >> k) & 1)
            if s > best:
                best = s
    return score == best

