function validate(args, output) {
    const numArrows = args[0], alice = args[1];
    if (!Array.isArray(output) || output.length !== 12) return false;
    for (const x of output) {
        if (!Number.isInteger(x) || x < 0) return false;
    }
    if (output.reduce((a, b) => a + b, 0) !== numArrows) return false;
    let score = 0;
    for (let k = 0; k < 12; k++) if (output[k] > alice[k]) score += k;
    let best = -1;
    for (let mask = 0; mask < (1 << 12); mask++) {
        let cost = 0;
        for (let k = 0; k < 12; k++) if ((mask >> k) & 1) cost += alice[k] + 1;
        if (cost <= numArrows) {
            let s = 0;
            for (let k = 0; k < 12; k++) if ((mask >> k) & 1) s += k;
            if (s > best) best = s;
        }
    }
    return score === best;
}

