    const bob = new Array(12).fill(0);
    let used = 0;
    for (let k = 0; k < 12; k++) {
        if (bestMask & (1 << k)) {
            bob[k] = aliceArrows[k] + 1;
            used += bob[k];
        }
    }
    bob[0] += numArrows - used;
    return bob;
